object InputValidator {

  // Reject any input containing shell metacharacters
  private val dangerousChars = Set(';', '&', '|', '`', '$', '(', ')', '{', '}', '<', '>', '!', '\\', '"', '\'', '\n', '\r', '\0')

  def validateArgument(arg: String, allowedPatterns: List[String]): Either[String, String] = {
    if (arg.isEmpty) {
      Left("Empty argument not allowed")
    } else if (arg.length > 256) {
      Left(s"Argument too long: max 256 characters, got ${arg.length}")
    } else if (arg.exists(dangerousChars.contains)) {
      Left(s"Argument contains forbidden characters: '$arg'")
    } else if (!allowedPatterns.exists(pattern => arg.matches(s"^$pattern$$"))) {
      Left(s"Argument '$arg' does not match any allowed pattern")
    } else {
      Right(arg)
    }
  }

  def validateAllArguments(args: List[String], allowedPatterns: List[String]): Either[String, List[String]] = {
    val results = args.map(arg => validateArgument(arg, allowedPatterns))
    val errors = results.collect { case Left(err) => err }
    if (errors.nonEmpty) {
      Left(s"Validation errors: ${errors.mkString("; ")}")
    } else {
      Right(results.collect { case Right(arg) => arg })
    }
  }
}

class SecureCommandExecutor(maxConcurrentCommands: Int = 5) {

  private val semaphore = new java.util.concurrent.Semaphore(maxConcurrentCommands)
  private val timeoutSeconds = 30

  // SECURE: Uses Process with sequence of arguments - NO shell interpolation
  def execute(request: CommandRequest): Either[String, CommandResult] = {
    // Step 1: Look up command in allowlist
    val allowedCommand = CommandRegistry.getCommand(request.commandName) match {
      case Some(cmd) => cmd
      case None =>
        return Left(s"Unknown command: '${request.commandName}'. Use listCommands to see available commands.")
    }

    // Step 2: Validate all arguments against allowed patterns
    val validatedArgs = InputValidator.validateAllArguments(
      request.arguments,
      allowedCommand.allowedArgPatterns
    ) match {
      case Right(args) => args
      case Left(error) => return Left(error)
    }

    // Step 3: Rate limiting
    if (!semaphore.tryAcquire()) {
      return Left("Too many concurrent commands. Please try again later.")
    }

    try {
      // Step 4: Execute using Process with argument list (NOT string interpolation)
      // This is the SECURE way - each argument is passed separately, preventing injection
      val commandSeq: Seq[String] = allowedCommand.executable +: validatedArgs

      val stdoutBuilder = new StringBuilder
      val stderrBuilder = new StringBuilder

      val processLogger = ProcessLogger(
        line => stdoutBuilder.append(line).append('\n'),
        line => stderrBuilder.append(line).append('\n')
      )

      // Use Process with a sequence of strings - no shell involved
      val process = Process(commandSeq)

      val exitCodeFuture = scala.concurrent.Future {
        process.!(processLogger)
      }(scala.concurrent.ExecutionContext.global)

      val exitCode = Try {
        scala.concurrent.Await.result(
          exitCodeFuture,
          scala.concurrent.duration.Duration(timeoutSeconds, "seconds")
        )
      } match {
        case Success(code) => code
        case Failure(_: java.util.concurrent.TimeoutException) =>
          return Left(s"Command timed out after $timeoutSeconds seconds")
        case Failure(ex) =>
          return Left(s"Command execution failed: ${ex.getMessage}")
      }

      Right(CommandResult(
        exitCode = exitCode,
        stdout = stdoutBuilder.toString().take(10000), // Limit output size
        stderr = stderrBuilder.toString().take(5000),
        success = exitCode == 0
      ))
    } finally {
      semaphore.release()
    }
  }

  def listCommands(): Map[String, String] = CommandRegistry.listAvailableCommands()
}

