// REST API adapter example (pseudo-code structure for integration)
object ApiAdapter {

  import scala.util.parsing.json._

  private val executor = new SecureCommandExecutor()

  /** Parse and handle a JSON request like: {"command": "disk-usage", "args": ["-h"]} */
  def handleRequest(jsonBody: String): String = {
    val parsed = JSON.parseFull(jsonBody)

    parsed match {
      case Some(map: Map[String @unchecked, Any @unchecked]) =>
        val commandName = map.get("command") match {
          case Some(s: String) => s
          case _ => return """{"error": "Missing or invalid 'command' field"}"""
        }
        val arguments = map.get("args") match {
          case Some(list: List[Any @unchecked]) => list.collect { case s: String => s }
          case None => List.empty[String]
          case _ => return """{"error": "Invalid 'args' field - must be array of strings"}"""
        }

        val request = CommandRequest(commandName, arguments)

        executor.execute(request) match {
          case Right(result) =>
            s"""{"success": ${result.success}, "exitCode": ${result.exitCode}, "stdout": "${escapeJson(result.stdout)}", "stderr": "${escapeJson(result.stderr)}"}"""
          case Left(error) =>
            s"""{"error": "${escapeJson(error)}"}"""
        }

      case _ =>
        """{"error": "Invalid JSON"}"""
    }
  }

  def handleListCommands(): String = {
    val commands = executor.listCommands()
    val entries = commands.map { case (name, desc) =>
      s""""$name": "${escapeJson(desc)}""""
    }.mkString(", ")
    s"""{$entries}"""
  }

  private def escapeJson(s: String): String =
    s.replace("\\", "\\\\")
      .replace("\"", "\\\"")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
}